/* Aula 24 — modelJs: Datas */

const agora = new Date();
console.log('agora:', agora);
console.log('timestamp(ms):', agora.getTime());

// 25 de dezembro de 2026 (mês 11 = dezembro)
const natal2026 = new Date(2026, 11, 25);
console.log('natal2026:', natal2026);
console.log('ano:', natal2026.getFullYear());
console.log('mes (0-11):', natal2026.getMonth());
console.log('dia:', natal2026.getDate());

// diferença em dias
const diffMs = natal2026.getTime() - agora.getTime();
const dias = Math.ceil(diffMs / 86400000);
console.log('dias até natal 2026:', dias);

// formatação pt-BR
const formatado = new Intl.DateTimeFormat('pt-BR', {
  dateStyle: 'full',
  timeStyle: 'short'
}).format(agora);
console.log('formatado:', formatado);

// função diasAte
function diasAte(dataIso) {
  const alvo = new Date(dataIso);
  const diff = alvo.getTime() - Date.now();
  return Math.ceil(diff / 86400000);
}

console.log('dias até 2026-03-10:', diasAte('2026-03-10'));
